/**
 * Custom hook that provides menu options for the experiment creation form.
 * Wraps the auto-generated tenant menus list hook.
 */
import { useMemo } from 'react';

import { isValueDefined } from '../../../utils/is';
import { useOnlineMenuWebMenuList } from '../../autoGeneratedHooks/onlinemenu/tenantmenus/tenantmenus';

export interface MenuOption {
  id: string;
  name: string;
}

interface UseMenuOptionsResult {
  menus: MenuOption[];
  isLoading: boolean;
}

export function useMenuOptions(): UseMenuOptionsResult {
  const { data, isLoading } = useOnlineMenuWebMenuList();

  const menus = useMemo((): MenuOption[] => {
    if (!isValueDefined(data?.menus)) return [];
    return data.menus
      .filter((m) => isValueDefined(m.externalId) && isValueDefined(m.name))
      .map((m) => ({ id: m.externalId ?? '', name: m.name ?? '' }));
  }, [data]);

  return { menus, isLoading };
}
